select count(*) from postgres.posthistory as ph, postgres.posts as p, postgres.users as u, postgres.badges as b where u.id = p.owneruserid and p.owneruserid = ph.userid and ph.userid = b.userid and ph.creationdate>=timestamp '2010-09-06 11:41:43' and ph.creationdate<=timestamp '2014-09-03 16:41:18' and p.score>=-1 and p.viewcount>=0 and p.viewcount<=39097 and p.answercount>=0 and p.commentcount>=0 and p.commentcount<=11 and p.favoritecount<=10 and p.creationdate>=timestamp '2010-08-13 02:18:09' and p.creationdate<=timestamp '2014-09-09 10:20:27' and u.views>=0 and u.downvotes>=0 and u.downvotes<=0 and u.upvotes>=0 and u.upvotes<=37;
